from itertools import combinations
class CombinatoricsSolver:
    def __init__(self, target):
        self.target = target
    def find_combinations(self, numbers, index, combination=[]):
        if self.check_combination(combination):
            return 1
        elif index >= len(numbers):
            return 0
        else:
            combinations_with = self.find_combinations(numbers, index + 1, combination + [numbers[index]])
            combinations_without = self.find_combinations(numbers, index + 1, combination)
            return combinations_with + combinations_without
    def check_combination(self, combination):
        return sum(combination) == self.target
