from collections import defaultdict
class SubSetCounter:
    def __init__(self, numbers):
        self.numbers = numbers
        self.count = 0
        self.gcds = self.compute_gcds()
    def compute_gcds(self):
        gcds = defaultdict(int)
        for num in self.numbers:
            gcd = 1
            for prime in range(2, num + 1):
                if num % prime == 0:
                    while num % prime == 0:
                        num //= prime
                    gcd *= prime
            gcds[gcd] += 1
        return gcds
    def is_perfect_square(self, gcd):
        for prime in range(2, gcd + 1):
            if gcd % prime == 0:
                while gcd % prime == 0:
                    gcd //= prime
                if gcd != 1:
                    return False
        return True
    def count_subsets(self):
        for gcd in self.gcds:
            if self.is_perfect_square(gcd):
                self.count += 1
        return self.count
def f(numbers: list):
    counter = SubSetCounter(numbers)
    return counter.count_subsets()

