        self.width = width
        self.height = height
class Envelope:
    def __init__(self, dimensions: list[tuple[int, int]]):
        self.stack = []
        for dim in dimensions:
            self.stack.append(Rectangle(*dim))
    def can_fit(self, test_rect: Rectangle, target_rect: Rectangle):
        if test_rect.width <= target_rect.width and test_rect.height <= target_rect.height or (test_rect.width <= target_rect.height and test_rect.height <= target_rect.width):
            return True
        return False
    def pop(self) -> Rectangle:
        return self.stack.pop()
    def push(self, rect: Rectangle):
        self.stack.append(rect)
    def last(self) -> Rectangle:
        return self.stack[-1]
def f(envelope_dimensions: list[tuple[int, int]]):
    envelope = Envelope(envelope_dimensions)
    stack_height = len(envelope_dimensions)
    for i in range(len(envelope_dimensions)):
        for j in range(i + 1, len(envelope_dimensions)):
            if envelope.can_fit(Rectangle(*envelope_dimensions[i]), Rectangle(*envelope_dimensions[j])):
                envelope.push(Rectangle(*envelope_dimensions[j]))
                envelope.pop()
                if envelope.can_fit(envelope.stack[-1], envelope.last()):
                    envelope.stack.pop()
                    stack_height = max(stack_height, len(envelope.stack) + 1)
                envelope.push(Rectangle(*envelope_dimensions[i]))
                envelope.push(Rectangle(*envelope_dimensions[j]))
    return stack_height

