    def process(state: dict):
        if not state:
            return 0
        cur_key = state['next_key']
        if cur_key in memo:
            memo[cur_key].append(state)
        memo.setdefault(cur_key, []).append(state)
        state['snapshots'].append(state)
        status_level = state['status_level']
        if status_level > 1:
            del state['snapshots'][-2:]
        return status_level > 1
    state = {'initial_count': 0, 'next_key': '', 'current_key': '', 'snapshots': [], 'status_level': 1}
