        self.numbers = numbers
        self.memo = {}
    def find_combinations(self, index, combination=[]):
        if self.check_combination(combination):
            return 1
        elif index >= len(self.numbers):
            return 0
        else:
            key = (index, str(combination))
            if key in self.memo:
                return self.memo[key]
            combinations_with = self.find_combinations(index + 1, combination + [self.numbers[index]])
            combinations_without = self.find_combinations(index + 1, combination)
            self.memo[key] = combinations_with + combinations_without
            return self.memo[key]
    def check_combination(self, combination):
        return sum(combination) == self.target
