        self.value = value
        self.left = None
        self.right = None
class BinarySearchTree:
    def __init__(self):
        self.root = None
    def insert(self, value):
        if self.root is None:
            self.root = BinaryTreeNode(value)
        else:
            self._insert_recursive(self.root, value)
    def _insert_recursive(self, current, value):
        if value < current.value:
            if current.left is None:
                current.left = BinaryTreeNode(value)
            else:
                self._insert_recursive(current.left, value)
        elif value > current.value:
            if current.right is None:
                current.right = BinaryTreeNode(value)
            else:
                self._insert_recursive(current.right, value)
    def find_longest_increasing_path(self):
        self._lcp = 0
        self._root = None
        self._find_lcp_recursive(self.root)
        return self._lcp
    def _find_lcp_recursive(self, node):
        if node is None or node.value is None:
            return 0
        left_path = self._find_lcp_recursive(node.left)
        right_path = self._find_lcp_recursive(node.right)
        path = left_path + right_path + 1
        self._lcp = max(self._lcp, path)
        return max(left_path, right_path) + 1
    def balance_tree(self):
        elements = []
        self._inorder_traversal(self.root, elements)
        self.root = self._sorted_array_to_bst(elements, 0, len(elements) - 1)
    def _inorder_traversal(self, node, elements):
        if node:
            self._inorder_traversal(node.left, elements)
            elements.append(node.value)
            self._inorder_traversal(node.right, elements)
    def _sorted_array_to_bst(self, elements, start, end):
        if start > end:
            return None
        mid = (start + end) // 2
        root = BinaryTreeNode(elements[mid])
        root.left = self._sorted_array_to_bst(elements, start, mid - 1)
        root.right = self._sorted_array_to_bst(elements, mid + 1, end)
        return root
    def get_balanced_count(self):
        self._balanced_count = 0
        self._count_balanced_nodes_recursive(self.root)
        return self._balanced_count
    def _count_balanced_nodes_recursive(self, node):
        if node is None:
            return 0
        left_height = self._get_height(node.left)
        right_height = self._get_height(node.right)
        if abs(left_height - right_height) <= 1:
            self._balanced_count += 1
        self._count_balanced_nodes_recursive(node.left)
        self._count_balanced_nodes_recursive(node.right)
    def _get_height(self, node):
        if node is None:
            return 0
        return 1 + max(self._get_height(node.left), self._get_height(node.right))
def f(input_list: list):
    bst = BinarySearchTree()
    for value in input_list:
        bst.insert(value)
    bst.balance_tree()
    longest_path = bst.find_longest_increasing_path()
    balanced_count = bst.get_balanced_count()
    return (longest_path, balanced_count)

