class PalindromicSubsequence:
    def __init__(self, string):
        self.string = string
        self.n = len(string)
        self.lps = [[0] * self.n for _ in range(self.n)]
    def longest_palindromic_subsequence(self):
        for i in range(self.n):
            self.lps[i][i] = 1
        for i in range(self.n - 1):
            if self.string[i] == self.string[i + 1]:
                self.lps[i][i + 1] = 2
            else:
                self.lps[i][i + 1] = 1
        for length in range(3, self.n + 1):
            for start in range(self.n - length + 1):
                end = start + length - 1
                if self.string[start] == self.string[end]:
                    self.lps[start][end] = 2 + self.lps[start + 1][end - 1]
                else:
                    self.lps[start][end] = max(self.lps[start][end - 1], self.lps[start + 1][end])
        return self.lps[0][self.n - 1]
