        self._update_node_values_recursive(self.root)
    def _update_node_values_recursive(self, node: TreeNode) -> None:
        if node.left:
            node.left.value = node.left.value + node.value
        if node.right:
            node.right.value = node.right.value + node.value
        if node.left:
            self._update_node_values_recursive(node.left)
        if node.right:
            self._update_node_values_recursive(node.right)
    def calculate_sum(self) -> int:
        return self._calculate_sum_recursive(self.root)
    def _calculate_sum_recursive(self, node: TreeNode) -> int:
        result = node.value
        if node.left:
            result += self._calculate_sum_recursive(node.left)
        if node.right:
            result += self._calculate_sum_recursive(node.right)
        return result
