class TreeNode:
    def __init__(self, value: int):
        self.value = value
        self.left = None
        self.right = None
class BinaryTree:
    def __init__(self):
        self.root = None
    def add_node(self, value: int) -> None:
        if self.root is None:
            self.root = TreeNode(value)
        else:
            self._add_node_recursive(self.root, value)
    def _add_node_recursive(self, node: TreeNode, value: int) -> None:
        if value < node.value:
            if node.left is None:
                node.left = TreeNode(value)
            else:
                self._add_node_recursive(node.left, value)
        elif node.right is None:
            node.right = TreeNode(value)
        else:
            self._add_node_recursive(node.right, value)
    def update_node_values(self) -> None:
        self._update_node_values_recursive(self.root)
    def _update_node_values_recursive(self, node: TreeNode) -> None:
        if node.left:
            node.left.value = node.left.value + node.value
        if node.right:
            node.right.value = node.right.value + node.value
        if node.left:
            self._update_node_values_recursive(node.left)
        if node.right:
            self._update_node_values_recursive(node.right)
    def calculate_sum(self) -> int:
        return self._calculate_sum_recursive(self.root)
    def _calculate_sum_recursive(self, node: TreeNode) -> int:
        result = node.value
        if node.left:
            result += self._calculate_sum_recursive(node.left)
        if node.right:
            result += self._calculate_sum_recursive(node.right)
        return result
def f(input_list: List[int]) -> int:
    tree = BinaryTree()
    for value in input_list:
        tree.add_node(value)
    tree.update_node_values()
