        n = len(self.sequence)
        if n == 0:
            return 0
        def dp(i: int) -> int:
            if i >= n:
                return 0
            if i in self.memo:
                return self.memo[i]
            if i == 0:
                self.memo[i] = self.sequence[i]
            else:
