def recursive_interval_processing(intervals, current_interval, max_interval):
    if not intervals:
        return max_interval
    next_interval = intervals[0]
    new_start = min(current_interval.start, next_interval.start)
    new_end = max(current_interval.end, next_interval.end)
    updated_interval = Interval(new_start, new_end)
    max_interval.start = max(max_interval.start, new_start)
    max_interval.end = min(max_interval.end, new_end)
    return recursive_interval_processing(intervals[1:], updated_interval, max_interval)
