        return StateTracker(new_string)
    def compress_consecutive_chars(self):
        new_string = ''
        count = 1
        for i in range(1, len(self.input_string)):
            if self.input_string[i] == self.input_string[i - 1]:
                count += 1
            else:
                new_string += self.input_string[i - 1] + str(count) if count > 1 else self.input_string[i - 1]
                count = 1
        new_string += self.input_string[-1] + str(count) if count > 1 else self.input_string[-1]
        return StateTracker(new_string)
    def anagramize_odd_position_chars(self):
        odd_chars = [char for (i, char) in enumerate(self.input_string) if i % 2 != 0]
        anagrams = set()
        for i in range(len(odd_chars)):
            for j in range(i + 1, len(odd_chars)):
                if odd_chars[i] + odd_chars[j] not in anagrams:
                    anagrams.add(odd_chars[i] + odd_chars[j])
        new_string = ''.join([char if i % 2 == 0 else next(iter(anagrams)) for (i, char) in enumerate(self.input_string)])
        return StateTracker(new_string)
