        from itertools import permutations
        freq = {}
        for char in self.input_string:
            freq[char] = freq.get(char, 0) + 1
        words = [''.join(p) for p in permutations(self.original)]
        for word in words:
            if ''.join(sorted(word)) == self.input_string:
                return StateTracker(word)
        return StateTracker(self.input_string)
