def buildTreeRecursive(nodes, index=0):
    if index >= len(nodes) or nodes[index] is None:
        return None
    tree = TreeNode(nodes[index])
    tree.left = buildTreeRecursive(nodes, 2 * index + 1)
    tree.right = buildTreeRecursive(nodes, 2 * index + 2)
    return tree
def inorderPostTraversal(node):
    if node is None:
        return []
    result = []
    stack = [node]
    while stack:
        current = stack.pop()
        if len(stack) and stack[-1] == current:
            while stack and stack[-1] == current and (stack[-1] in [node.left, node.right]):
                stack.pop()
                (current, result) = (result[-1], result + [result.pop()])
            if stack:
                if stack[-1] == node.left:
                    stack[-1] = current
                else:
                    stack.append(current)
                    stack.append(node.right)
        else:
            result.append(current.val)
    return result
def f(nodes):
    root = buildTreeRecursive(nodes)
    return inorderPostTraversal(root)

