class TreeNode:
    def __init__(self, value: int, parent: Dict[str, Any]=None):
        self.value = value
        self.parent = parent
        self.children: List['TreeNode'] = []
def build_tree(nodes: List[Dict[str, int]]) -> TreeNode:
    root = None
    node_map = {}
    for node_data in nodes:
        value = node_data['value']
        parent_value = node_data.get('parent', None)
        if value not in node_map:
            node_map[value] = TreeNode(value)
        if parent_value is not None:
            if parent_value not in node_map:
                node_map[parent_value] = TreeNode(parent_value)
            node_map[parent_value].children.append(node_map[value])
        else:
            root = node_map[value]
    return root
def max_path_sum(node: TreeNode, threshold: int) -> int:
    if node is None:
        return 0
    if node.children:
        return max((max_path_sum(child, threshold) + node.value for child in node.children))
    return node.value if node.value > threshold else 0
def f(tree_nodes: List[Dict[str, int]], threshold: int=10) -> int:
    root = build_tree(tree_nodes)
    return max_path_sum(root, threshold)

