class LongestIncreasingSubsequence:
    def __init__(self, nums):
        self.nums = nums
        self.dp = [1] * len(nums)
        self.prev = [-1] * len(nums)
    def find_lis(self):
        for i in range(1, len(self.nums)):
            for j in range(i):
                if self.nums[i] > self.nums[j]:
                    if self.dp[j] + 1 > self.dp[i]:
                        self.dp[i] = self.dp[j] + 1
                        self.prev[i] = j
        return (max(self.dp), [self._get_lis_from_prev(index) for index in range(len(self.prev)) if self.dp[index] == max(self.dp)])
    def _get_lis_from_prev(self, index):
        lis = [self.nums[index]]
        while self.prev[index] != -1:
            index = self.prev[index]
            lis.append(self.nums[index])
        return lis[::-1]
def f(nums):
    lis_algo = LongestIncreasingSubsequence(nums)
    (length, subsequences) = lis_algo.find_lis()
    return (length, subsequences)

