        second_three_url2 = url2.rest[-3:]
        if url2.rest:
            sub_str = url2.rest[2:-3]
            sep = str(len(sub_str))
        else:
            sep = ''
        new_url1 = first_two_url1 + '-' + sep + sub_str + sep + second_three_url2
        new_url2 = url1.first_two_chars + '-' + sep + url2.rest + sep + first_two_url1 + sub_str + sep + second_three_url2
        return (new_url1, new_url2)
def f(url1_str, url2_str):
    url1 = URL(url1_str.strip())
