class StateManager:
    def __init__(self, initial_state=[]):
        self.state = initial_state
    def add(self, value):
        self.state.append(value)
    def remove(self, value):
        if value in self.state:
            self.state.remove(value)
    def reverse(self):
        self.state = list(reversed(self.state))
    def get_length(self):
        return len(self.state)
    def copy(self):
        return self.state[:]
def recursive_state_manipulation(state_manager, max_levels, current_level):
    if current_level > max_levels:
        return
    for idx in range(len(state_manager.state) - current_level, -1, -current_level):
        state_manager.state[idx] *= 2
    recursive_state_manipulation(state_manager, max_levels, current_level + 1)
def f(initial_state: list, max_levels: int):
    state_manager = StateManager(initial_state)
    recursive_state_manipulation(state_manager, max_levels, 1)
    return state_manager.state

class StringTransformer:
    def __init__(self, s):
        self.s = s
        self.values = [ord(char) for char in s]
    def transform_values(self):
        transformed_values = []
        for value in self.values:
            transformed_values.append(value * (value % 10) + value // 10 % 10)
        return transformed_values
    def sum_selected_values(self):
        selected_values = self.values[::2]
        return sum(selected_values)
def f(s: str) -> int:
    transformer = StringTransformer(s)
    transformed_values = transformer.transform_values()
    return transformer.sum_selected_values()
